import express from 'express';
import crypto from 'crypto';

const app = express();
const SECRET_KEY = process.env.SECRET_KEY || 'your-secret-key-change-in-production';

// Generate a shareable link for a document
function generateShareableLink(documentId, baseUrl = 'http://localhost:3000') {
  // Create the payload
  const payload = documentId;

  // Generate HMAC signature
  const signature = crypto
    .createHmac('sha256', SECRET_KEY)
    .update(payload)
    .digest('hex');

  // Create the token in payload.signature format
  const token = `${payload}.${signature}`;

  // Return the shareable URL
  return `${baseUrl}/share/${token}`;
}

// Verify and decode a token
function verifyToken(token) {
  const parts = token.split('.');

  if (parts.length !== 2) {
    return null;
  }

  const [payload, signature] = parts;

  // Regenerate the signature to verify
  const expectedSignature = crypto
    .createHmac('sha256', SECRET_KEY)
    .update(payload)
    .digest('hex');

  // Use timingSafeEqual for constant-time comparison
  try {
    const signatureBuffer = Buffer.from(signature, 'hex');
    const expectedBuffer = Buffer.from(expectedSignature, 'hex');

    if (!crypto.timingSafeEqual(signatureBuffer, expectedBuffer)) {
      return null;
    }
  } catch (err) {
    return null;
  }

  return payload;
}

// Express middleware to verify share tokens
function verifyShareToken(req, res, next) {
  const token = req.params.token;
  const documentId = verifyToken(token);

  if (!documentId) {
    return res.status(401).json({ error: 'Invalid or expired share link' });
  }

  req.documentId = documentId;
  next();
}

// Routes
app.get('/generate-share/:documentId', (req, res) => {
  const { documentId } = req.params;
  const shareUrl = generateShareableLink(documentId);
  res.json({ shareUrl });
});

app.get('/share/:token', verifyShareToken, (req, res) => {
  const documentId = req.documentId;
  res.json({ 
    message: 'Document access granted',
    documentId: documentId,
    content: `This is the content of document ${documentId}`
  });
});

// Start server
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
  console.log(`Example: Generate a share link with GET /generate-share/doc123`);
});
