```javascript
import Anthropic from "@anthropic-ai/sdk";
import crypto from "crypto";
import express from "express";

const client = new Anthropic();
const app = express();

// In-memory storage for share tokens and documents
const shareTokens = new Map();
const documents = new Map();

// Initialize with some sample documents
documents.set("doc1", { id: "doc1", title: "Sample Document 1", content: "This is a sample document" });
documents.set("doc2", { id: "doc2", title: "Sample Document 2", content: "This is another sample document" });

// Function to generate a shareable link for a document
function generateShareableLink(documentId) {
  // Check if document exists
  if (!documents.has(documentId)) {
    throw new Error(`Document with ID ${documentId} not found`);
  }

  // Generate a unique token
  const token = crypto.randomBytes(16).toString("hex");

  // Store the mapping between token and document ID
  shareTokens.set(token, documentId);

  // Return the shareable URL
  return `/share/${token}`;
}

// Express route to view a shared document
app.get("/share/:token", (req, res) => {
  const { token } = req.params;

  // Check if token exists
  if (!shareTokens.has(token)) {
    return res.status(404).json({ error: "Document not found or link expired" });
  }

  // Get the document ID from the token
  const documentId = shareTokens.get(token);

  // Get the document
  const document = documents.get(documentId);

  if (!document) {
    return res.status(404).json({ error: "Document not found" });
  }

  // Return the document
  res.json({
    success: true,
    document: document,
    shareToken: token,
  });
});

// Function to use Claude for generating share links with explanation
async function generateShareLinkWithExplanation(documentId) {
  const shareLink = generateShareableLink(documentId);

  // Use Claude to generate a helpful message about the share link
  const message = await client.messages.create({
    model: "claude-3-5-sonnet-20241022",
    max_tokens: 1024,
    messages: [
      {
        role: "user",
        content: `I just generated a shareable link for a document. The document ID is "${documentId}" and the shareable link is "${shareLink}". 

Please provide a brief, friendly explanation of what this link does and how it can be used. Keep it to 2-3 sentences.`,
      },
    ],
  });

  const explanation = message.content[0].type === "text" ? message.content[0].text : "";

  return {
    documentId,
    shareLink,
    explanation,
  };
}

// Main execution
async function main() {
  try {
    // Generate a shareable link for document 1
    console.log("Generating shareable link for document 1...\n");
    const result = await generateShareLinkWithExplanation("doc1");

    console.log("Document ID:", result.documentId);
    console.log("Shareable Link:", result.shareLink);
    console.log("Explanation:", result.explanation);
    console.log("\n---\n");

    // Generate another shareable link for document 2
    console.log("Generating shareable link for document 2...\n");
    const result2 = await generateShareLinkWithExplanation("doc2");

    console.log("Document ID:", result2.documentId);
    console.log("Shareable Link:", result2.shareLink);
    console.log("Explanation:", result2.explanation);
    console.log("\n---\n");

    // Start the Express server
    const PORT = 3000;
    app.listen(PORT, () => {
      console.log(`Server running on http://localhost:${PORT}`);
      console.log(`\nYou can test the share links:`);
      console.log(`- ${result.shareLink}`);
      console.log(`- ${result2.shareLink}`);
    });
  } catch (error) {
    console.error("Error:", error.message);
    process.exit(1);
  }
}

main();
