            print(f"[{datetime.now().isoformat()}] Sending notification {notification['id']} to {notification['recipient']}")

            # Mark as sent in database
            for n in notifications_db:
                if n["id"] == notification["id"]:
                    n["status"] = "sent"
                    sent_count += 1
                    break

        except Exception as e:
            print(f"[{datetime.now().isoformat()}] Error sending notification {notification['id']}: {str(e)}")
            failed_count += 1

    # Handle failed validations
    for failed in validation_result.get("failed_notifications", []):
        print(f"[{datetime.now().isoformat()}] Notification {failed['id']} validation failed: {failed.get('reason', 'Unknown reason')}")
        failed_count += 1

    print(f"[{datetime.now().isoformat()}] Cron job completed: {sent_count} sent, {failed_count} failed")

    return {
        "sent": sent_count,
        "failed": failed_count,
        "total_processed": sent_count + failed_count
    }


if __name__ == "__main__":
    # Run the cron job
    result = send_queued_notifications()
    print(f"\nFinal result: {result}")
