CREATE FUNCTION get_public_event(p_token TEXT)
RETURNS TABLE(
  id BIGINT,
  title TEXT,
  description TEXT,
  max_capacity INT,
  rsvp_count BIGINT
) SECURITY DEFINER SET search_path = public AS $$
  SELECT
    e.id,
    e.title,
    e.description,
    e.max_capacity,
    COALESCE(COUNT(r.id), 0)::BIGINT as rsvp_count
  FROM events e
  LEFT JOIN rsvps r ON e.id = r.event_id AND r.status = 'confirmed'
  WHERE e.public_token = p_token AND e.public_token IS NOT NULL
  GROUP BY e.id, e.title, e.description, e.max_capacity
  LIMIT 1;
$$ LANGUAGE SQL;

GRANT EXECUTE ON FUNCTION get_public_event(TEXT) TO anon;

CREATE FUNCTION list_public_events()
RETURNS TABLE(
  id BIGINT,
  title TEXT,
  description TEXT,
  max_capacity INT,
  rsvp_count BIGINT,
  public_token TEXT
) SECURITY DEFINER SET search_path = public AS $$
  SELECT
    e.id,
    e.title,
    e.description,
    e.max_capacity,
    COALESCE(COUNT(r.id), 0)::BIGINT as rsvp_count,
    e.public_token
  FROM events e
  LEFT JOIN rsvps r ON e.id = r.event_id AND r.status = 'confirmed'
  WHERE e.public_token IS NOT NULL
  GROUP BY e.id, e.title, e.description, e.max_capacity, e.public_token;
$$ LANGUAGE SQL;

