CREATE FUNCTION submit_public_rsvp(p_token TEXT, p_name TEXT, p_email TEXT)
RETURNS TABLE(
  success BOOLEAN,
  message TEXT,
  rsvp_id BIGINT
) SECURITY DEFINER SET search_path = public AS $$
DECLARE
  v_event_id BIGINT;
  v_rsvp_id BIGINT;
  v_current_count INT;
BEGIN
  SELECT e.id INTO v_event_id
  FROM events e
  WHERE e.public_token = p_token AND e.public_token IS NOT NULL
  LIMIT 1;

  IF v_event_id IS NULL THEN
    RETURN QUERY SELECT FALSE, 'Event not found'::TEXT, NULL::BIGINT;
    RETURN;
  END IF;

  SELECT COUNT(*)::INT INTO v_current_count
  FROM rsvps
  WHERE event_id = v_event_id AND status = 'confirmed';

  SELECT max_capacity INTO v_current_count
  FROM events
  WHERE id = v_event_id;

  IF v_current_count >= (SELECT max_capacity FROM events WHERE id = v_event_id) THEN
    RETURN QUERY SELECT FALSE, 'Event is at capacity'::TEXT, NULL::BIGINT;
    RETURN;
  END IF;

  INSERT INTO rsvps (event_id, name, email, status)
  VALUES (v_event_id, p_name, p_email, 'confirmed')
  RETURNING rsvps.id INTO v_rsvp_id;

  RETURN QUERY SELECT TRUE, 'RSVP submitted successfully'::TEXT, v_rsvp_id;
END;
$$ LANGUAGE PLPGSQL;

GRANT EXECUTE ON FUNCTION submit_public_rsvp(TEXT, TEXT, TEXT) TO anon;

