CREATE SCHEMA IF NOT EXISTS public;

-- Create the photos table if it doesn't exist
CREATE TABLE IF NOT EXISTS public.photos (
  id BIGSERIAL PRIMARY KEY,
  photographer_id BIGINT NOT NULL,
  url TEXT NOT NULL,
  caption TEXT,
  is_portfolio BOOLEAN DEFAULT FALSE,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- Enable Row Level Security
ALTER TABLE public.photos ENABLE ROW LEVEL SECURITY;

-- Create a policy for anonymous users to view only portfolio photos
CREATE POLICY "Allow anonymous users to view portfolio photos"
  ON public.photos
  FOR SELECT
  USING (is_portfolio = TRUE);

-- Create a policy for authenticated users (photographers) to manage their own photos
CREATE POLICY "Allow photographers to manage their own photos"
  ON public.photos
  FOR ALL
  USING (auth.uid()::text = photographer_id::text)
  WITH CHECK (auth.uid()::text = photographer_id::text);

-- Grant SELECT permission to anonymous users (anon role)
GRANT SELECT ON public.photos TO anon;

-- Grant all permissions to authenticated users
GRANT ALL ON public.photos TO authenticated;

-- Create an index for better query performance
CREATE INDEX IF NOT EXISTS idx_photos_is_portfolio ON public.photos(is_portfolio);
CREATE INDEX IF NOT EXISTS idx_photos_photographer_id ON public.photos(photographer_id);
