app.get('/health', (req, res) => {
  res.json({ status: 'Express server is running' });
});

app.listen(PORT, () => {
  console.log(`Express proxy server listening on port ${PORT}`);
  console.log(`Proxying /api/* requests to http://localhost:5000`);
});
