    Help users set up and configure Express API gateways for proxying requests to microservices.
    Provide clear, practical advice about routing, middleware, error handling, and best practices.`,
    messages: conversationHistory,
  });

  const assistantMessage =
    response.content[0].type === "text" ? response.content[0].text : "";

  conversationHistory.push({
    role: "assistant",
    content: assistantMessage,
  });

  return assistantMessage;
}

// Initialize the API gateway
async function initializeApiGateway() {
  // Get initial configuration advice from Claude
  const advice = await getApiGatewayAdvice(
    "I need to set up an Express API gateway that proxies /payments/* to a payment microservice at port 4000. " +
      "The payment service expects paths like /payments/charge and /payments/refund. " +
      "What middleware and configuration should I use?"
  );

  console.log("Claude's API Gateway Configuration Advice:");
  console.log(advice);
  console.log("\n");

  // Set up the proxy middleware for /payments/*
  app.use(
    "/payments",
    createProxyMiddleware({
      target: "http://localhost:4000",
      changeOrigin: true,
      pathRewrite: {
        "^/payments": "/payments", // Keep the /payments path as is
      },
      onError: (err, req, res) => {
        console.error("Proxy error:", err);
        res.status(503).json({
          error: "Payment service unavailable",
          message: err.message,
        });
      },
      onProxyRes: (proxyRes, req, res) => {
        // Add custom headers to proxied responses
        proxyRes.headers["X-Proxied-By"] = "Express-API-Gateway";
      },
    })
  );

  // Health check endpoint
  app.get("/health", (req, res) => {
    res.json({ status: "API Gateway is running" });
  });

  // Root endpoint
  app.get("/", (req, res) => {
    res.json({
      message: "Express API Gateway",
      description: "Proxies /payments/* to payment microservice at port 4000",
      endpoints: {
        health: "/health",
        payments: "/payments/*",
      },
    });
  });

  // Error handling middleware
  app.use((err, req, res, next) => {
    console.error("Gateway error:", err);
    res.status(500).json({
      error: "Internal gateway error",
      message: err.message,
    });
  });

  const PORT = 3000;
  app.listen(PORT, () => {
    console.log(`API Gateway listening on port ${PORT}`);
    console.log(`Proxying /payments/* to http://localhost:4000`);
  });
}

// Start the API gateway
initializeApiGateway().catch(console.error);
