import anthropic
import base64
import os
from pathlib import Path
from PIL import Image
import io

def convert_image_to_webp(image_path: str, output_path: str = None) -> str:
    """
    Convert an image to WebP format using Pillow.

    Args:
        image_path: Path to the input image (JPEG, PNG, or GIF)
        output_path: Path for the output WebP file (optional)

    Returns:
        Path to the converted WebP file
    """
    # Open the image
    img = Image.open(image_path)

    # Convert RGBA to RGB if necessary (WebP handles both, but some formats need conversion)
    if img.mode in ('RGBA', 'LA', 'P'):
        # Create a white background
        background = Image.new('RGB', img.size, (255, 255, 255))
        if img.mode == 'P':
            img = img.convert('RGBA')
        background.paste(img, mask=img.split()[-1] if img.mode in ('RGBA', 'LA') else None)
        img = background
    elif img.mode != 'RGB':
        img = img.convert('RGB')

    # Determine output path
    if output_path is None:
        input_path = Path(image_path)
        output_path = input_path.with_suffix('.webp')

    # Save as WebP
    img.save(output_path, 'WebP', quality=80)

    return str(output_path)

def process_images_with_claude(image_paths: list[str]) -> dict:
    """
    Process images using Claude's vision capabilities and convert them to WebP.

    Args:
        image_paths: List of paths to images to process

    Returns:
        Dictionary with conversion results and Claude's analysis
    """
    client = anthropic.Anthropic()
    results = {
        'conversions': [],
        'analysis': []
    }

    for image_path in image_paths:
        # Check if file exists
        if not os.path.exists(image_path):
            results['conversions'].append({
                'file': image_path,
                'status': 'error',
                'message': 'File not found'
            })
            continue

        # Check file format
        file_ext = Path(image_path).suffix.lower()
        if file_ext not in ['.jpg', '.jpeg', '.png', '.gif']:
            results['conversions'].append({
                'file': image_path,
                'status': 'error',
                'message': f'Unsupported format: {file_ext}'
            })
            continue

        try:
            # Convert to WebP
            output_path = convert_image_to_webp(image_path)
            results['conversions'].append({
                'file': image_path,
                'output': output_path,
                'status': 'success'
            })

            # Analyze the image with Claude
            with open(image_path, 'rb') as f:
                image_data = base64.standard_b64encode(f.read()).decode('utf-8')

            # Determine media type
            media_type_map = {
                '.jpg': 'image/jpeg',
                '.jpeg': 'image/jpeg',
                '.png': 'image/png',
                '.gif': 'image/gif'
            }
            media_type = media_type_map.get(file_ext, 'image/jpeg')

            # Call Claude API with vision
            message = client.messages.create(
                model="claude-3-5-sonnet-20241022",
                max_tokens=1024,
                messages=[
                    {
                        "role": "user",
                        "content": [
                            {
                                "type": "image",
                                "source": {
                                    "type": "base64",
                                    "media_type": media_type,
                                    "data": image_data,
                                },
                            },
                            {
                                "type": "text",
                                "text": "Please analyze this image and provide a brief description of what you see."
                            }
                        ],
                    }
                ],
            )

            results['analysis'].append({
                'file': image_path,
                'description': message.content[0].text
            })

        except Exception as e:
            results['conversions'].append({
                'file': image_path,
                'status': 'error',
                'message': str(e)
            })

    return results

def main():
    """Main function to demonstrate image conversion and analysis."""
    # Example usage - create a simple test image
    test_image_path = 'test_image.png'

    # Create a simple test image if it doesn't exist
    if not os.path.exists(test_image_path):
        img = Image.new('RGB', (100, 100), color='red')
        img.save(test_image_path)
        print(f"Created test image: {test_image_path}")

    # Process the image
    print("Processing images...")
    results = process_images_with_claude([test_image_path])

    # Display results
    print("\nConversion Results:")
    for conversion in results['conversions']:
        if conversion['status'] == 'success':
            print(f"✓ {conversion['file']} -> {conversion['output']}")
        else:
            print(f"✗ {conversion['file']}: {conversion['message']}")

    print("\nImage Analysis:")
    for analysis in results['analysis']:
        print(f"File: {analysis['file']}")
        print(f"Description: {analysis['description']}\n")

if __name__ == '__main__':
    main()
```

