    def __repr__(self):
        return f'<User {self.username}>'

def send_welcome_email(user):
    """Send welcome email to new user"""
    try:
        subject = f"Welcome to Our App, {user.username}!"

        # Create email message
        msg = Message(
            subject=subject,
            recipients=[user.email],
            html=render_template('welcome_email.html', user=user)
        )

        # Send email
        mail.send(msg)

        # Mark email as sent
        user.welcome_email_sent = True
        db.session.commit()

        return True
    except Exception as e:
        print(f"Error sending email: {str(e)}")
        return False

@app.route('/')
def index():
    """Home page"""
    return render_template('index.html')

@app.route('/register', methods=['POST'])
def register():
    """Register a new user and send welcome email"""
    try:
        data = request.get_json()
        username = data.get('username')
        email = data.get('email')

        # Validate input
        if not username or not email:
            return jsonify({'success': False, 'message': 'Username and email are required'}), 400

        # Check if user already exists
        existing_user = User.query.filter_by(email=email).first()
        if existing_user:
            return jsonify({'success': False, 'message': 'Email already registered'}), 400

        # Create new user
        user = User(username=username, email=email)
        db.session.add(user)
        db.session.commit()

        # Send welcome email
        email_sent = send_welcome_email(user)

        if email_sent:
            return jsonify({
                'success': True,
                'message': f'Welcome email sent to {email}',
                'user_id': user.id
            }), 201
        else:
            return jsonify({
                'success': False,
                'message': 'User created but welcome email could not be sent'
            }), 201

    except Exception as e:
        db.session.rollback()
        return jsonify({'success': False, 'message': str(e)}), 500

