from flask import Flask, render_template, request, jsonify
from celery import Celery
from redis import Redis
import os
from datetime import datetime

app = Flask(__name__)
app.config['CELERY_BROKER_URL'] = os.environ.get('CELERY_BROKER_URL', 'redis://localhost:6379/0')
app.config['CELERY_RESULT_BACKEND'] = os.environ.get('CELERY_RESULT_BACKEND', 'redis://localhost:6379/0')

celery = Celery(app.name, broker=app.config['CELERY_BROKER_URL'])
celery.conf.update(app.config)

redis_client = Redis.from_url(app.config['CELERY_BROKER_URL'])


@celery.task(bind=True)
def long_running_task(self, duration):
    """Simulate a long-running task"""
    try:
        self.update_state(state='PROGRESS', meta={'current': 0, 'total': duration})
        for i in range(duration):
            self.update_state(state='PROGRESS', meta={'current': i + 1, 'total': duration})
        return {'status': 'Task completed!', 'result': f'Processed {duration} items'}
    except Exception as exc:
        self.update_state(state='FAILURE', meta={'exc_type': type(exc).__name__, 'exc_message': str(exc)})
        raise


@celery.task
def send_email_task(email, subject, body):
    """Simulate sending an email"""
    import time
    time.sleep(2)
    return {
        'status': 'Email sent',
        'email': email,
        'subject': subject,
        'timestamp': datetime.now().isoformat()
    }


@celery.task
def process_data_task(data):
    """Process data in background"""
    import time
    time.sleep(1)
    processed = {
        'original': data,
        'processed_at': datetime.now().isoformat(),
        'item_count': len(data) if isinstance(data, list) else 1
    }
    return processed


@app.route('/')
def index():
    """Home page"""
    return render_template('index.html')


@app.route('/api/task/long-running', methods=['POST'])
def start_long_running_task():
    """Start a long-running background task"""
    data = request.get_json()
    duration = data.get('duration', 10)

    task = long_running_task.delay(duration)

    return jsonify({
        'task_id': task.id,
        'status': 'Task started'
    }), 202


@app.route('/api/task/email', methods=['POST'])
def start_email_task():
    """Start an email sending task"""
    data = request.get_json()
    email = data.get('email')
    subject = data.get('subject', 'Hello')
    body = data.get('body', 'This is a test email')

    task = send_email_task.delay(email, subject, body)

    return jsonify({
        'task_id': task.id,
        'status': 'Email task started'
    }), 202


@app.route('/api/task/process', methods=['POST'])
def start_process_task():
    """Start a data processing task"""
    data = request.get_json()
    items = data.get('items', [])

    task = process_data_task.delay(items)

    return jsonify({
        'task_id': task.id,
        'status': 'Processing task started'
    }), 202


@app.route('/api/task/<task_id>', methods=['GET'])
def get_task_status(task_id):
    """Get the status of a task"""
    task = long_running_task.AsyncResult(task_id)

    if task.state == 'PENDING':
        response = {
            'state': task.state,
            'current': 0,
            'total': 100,
            'status': 'Task is waiting to be executed...'
        }
    elif task.state == 'PROGRESS':
        response = {
            'state': task.state,
            'current': task.info.get('current', 0),
            'total': task.info.get('total', 100),
            'status': f"Processing... {task.info.get('current', 0)}/{task.info.get('total', 100)}"
        }
    elif task.state == 'SUCCESS':
        response = {
            'state': task.state,
            'current': 100,
            'total': 100,
            'status': 'Task completed!',
            'result': task.result
        }
    elif task.state == 'FAILURE':
        response = {
            'state': task.state,
            'current': 0,
            'total': 100,
            'status': 'Task failed!',
            'error': str(task.info)
        }
    else:
        response = {
            'state': task.state,
            'status': f'Task state: {task.state}'
        }

    return jsonify(response)


@app.route('/api/task/<task_id>/result', methods=['GET'])
def get_task_result(task_id):
    """Get the result of a completed task"""
    task = long_running_task.AsyncResult(task_id)

    if task.state == 'SUCCESS':
        return jsonify({
            'status': 'success',
            'result': task.result
        })
    elif task.state == 'FAILURE':
        return jsonify({
            'status': 'failure',
            'error': str(task.info)
        }), 400
    else:
        return jsonify({
            'status': 'pending',
            'state': task.state
        }), 202


@app.route('/api/health', methods=['GET'])
def health_check():
    """Health check endpoint"""
    try:
        redis_client.ping()
        return jsonify({
            'status': 'healthy',
            'redis': 'connected',
            'timestamp': datetime.now().isoformat()
        })
    except Exception as e:
        return jsonify({
            'status': 'unhealthy',
            'error': str(e)
        }), 503


@app.errorhandler(404)
def not_found(error):
    """Handle 404 errors"""
    return jsonify({'error': 'Not found'}), 404


@app.errorhandler(500)
def internal_error(error):
    """Handle 500 errors"""
    return jsonify({'error': 'Internal server error'}), 500


if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)
