        return jsonify({
            "order": orders_db[order_id],
            "ai_insight": ai_response
        }), 200
    else:
        return jsonify({
            "error": f"Order {order_id} not found",
            "ai_insight": ai_response
        }), 404

@bp.route('/', methods=['POST'])
def create_order():
    """Create a new order."""
    data = request.get_json()

    ai_response = get_ai_response(f"User is creating a new order with customer: {data.get('customer', 'Unknown')} and total: ${data.get('total', 0)}. What validation should be done?")

