        content: `Generate a URL-friendly slug from this title: "${title}". Return only the slug, no other text. The slug should be lowercase, use hyphens instead of spaces, and contain only alphanumeric characters and hyphens.`,
      },
    ],
  });

  const slug = message.content[0].text.trim().toLowerCase();

  const newPost = { slug, title, content };
  posts.push(newPost);

  res.status(201).json(newPost);
});

// PUT /:slug - Update post
router.put("/:slug", async (req, res) => {
  const { title, content } = req.body;
  const postIndex = posts.findIndex((p) => p.slug === req.params.slug);

  if (postIndex === -1) {
    return res.status(404).json({ error: "Post not found" });
  }

  if (!title && !content) {
    return res
      .status(400)
      .json({ error: "At least title or content is required" });
  }

  // If title is being updated, generate a new slug
  if (title && title !== posts[postIndex].title) {
    const message = await client.messages.create({
      model: "claude-3-5-sonnet-20241022",
      max_tokens: 100,
      messages: [
        {
          role: "user",
          content: `Generate a URL-friendly slug from this title: "${title}". Return only the slug, no other text. The slug should be lowercase, use hyphens instead of spaces, and contain only alphanumeric characters and hyphens.`,
        },
      ],
    });

    const newSlug = message.content[0].text.trim().toLowerCase();
    posts[postIndex].slug = newSlug;
  }

  if (title) {
    posts[postIndex].title = title;
  }
  if (content) {
    posts[postIndex].content = content;
  }

  res.json(posts[postIndex]);
});

export default router;
